class Node:
    def __init__(self, data):
        self.data = data
        self.prev = None
        self.next = None

class DoublyLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None
        self._length = 0

    def __len__(self):
        return self._length

    def __iter__(self):
        current = self.head
        while current:
            yield current.data
            current = current.next

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            self.tail = new_node
        else:
            self.tail.next = new_node
            new_node.prev = self.tail
            self.tail = new_node
        self._length += 1

    def prepend(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            self.tail = new_node
        else:
            new_node.next = self.head
            self.head.prev = new_node
            self.head = new_node
        self._length += 1

    def delete(self, key):
        if not self.head:
            raise ValueError("List is empty")

        current = self.head
        while current:
            if current.data == key:
                # Found the node to delete
                if current.prev:
                    current.prev.next = current.next
                else:
                    # Deleting head
                    self.head = current.next

                if current.next:
                    current.next.prev = current.prev
                else:
                    # Deleting tail
                    self.tail = current.prev

                # Cleanup links just in case, though Python GC handles memory
                current.prev = None
                current.next = None
                self._length -= 1
                return True # Indicate success/deletion
            current = current.next

        raise ValueError(f"{key} not found in the list")

    def reverse(self):
        if self._length < 2:
            return

        # Swap next and prev pointers for all nodes
        current = self.head
        while current:
            temp = current.next
            current.next = current.prev
            current.prev = temp

            # Advance to the original next node (which is now stored in temp)
            current = temp

        # Swap head and tail pointers after reversing all links
        self.head, self.tail = self.tail, self.head

    def __str__(self):
        return str(list(self))

